import{_ as a,c as s,o as l,ag as t}from"./chunks/framework.B-XtCDNB.js";const h=JSON.parse('{"title":"Structured Writes","description":"","frontmatter":{},"headers":[],"relativePath":"capabilities/structured-writes.md","filePath":"capabilities/structured-writes.md"}'),n={name:"capabilities/structured-writes.md"};function o(p,e,r,i,c,d){return l(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="structured-writes" tabindex="-1">Structured Writes <a class="header-anchor" href="#structured-writes" aria-label="Permalink to &quot;Structured Writes&quot;">​</a></h1><p>Structured writes are one of LinkedQL&#39;s most application-oriented language features.</p><p>They let you express relationship-aware writes directly in SQL-shaped DML instead of splitting the operation across:</p><ul><li>multiple imperative inserts</li><li>foreign-key bookkeeping</li><li>extra query-roundtrips just to wire ids together</li></ul><p>The key idea is that DeepRef syntax is not just for reading. It can also appear in write targets.</p><h2 id="the-core-idea" tabindex="-1">The core idea <a class="header-anchor" href="#the-core-idea" aria-label="Permalink to &quot;The core idea&quot;">​</a></h2><p>A regular insert target looks like this:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">INSERT INTO</span><span style="color:#BABED8;"> public.users (id, email)</span></span>
<span class="line"><span style="color:#F78C6C;">VALUES</span><span style="color:#BABED8;"> (</span><span style="color:#F78C6C;">1</span><span style="color:#BABED8;">, </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">ada@example.com</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span></span></code></pre></div><p>A structured write target can include relational paths:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">INSERT INTO</span><span style="color:#BABED8;"> public.users</span></span>
<span class="line"><span style="color:#BABED8;">  (email, parent_user1 ~</span><span style="color:#89DDFF;">&gt;</span><span style="color:#BABED8;"> (id, email))</span></span>
<span class="line"><span style="color:#F78C6C;">VALUES</span></span>
<span class="line"><span style="color:#BABED8;">  (</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">ada@example.com</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">, </span><span style="color:#F78C6C;">ROW</span><span style="color:#BABED8;"> (</span><span style="color:#F78C6C;">50</span><span style="color:#BABED8;">, </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">parent@example.com</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">))</span></span></code></pre></div><p>That tells LinkedQL:</p><ul><li>insert a row into <code>public.users</code></li><li>also ensure the related <code>parent_user1</code> payload is written</li><li>wire the relationship through the appropriate key path</li></ul><h2 id="why-this-exists" tabindex="-1">Why this exists <a class="header-anchor" href="#why-this-exists" aria-label="Permalink to &quot;Why this exists&quot;">​</a></h2><p>Without structured writes, relationship-aware writes usually move into application code:</p><ol><li>insert one row</li><li>collect its id</li><li>insert another row</li><li>collect another id</li><li>update the linking row</li></ol><p>Structured writes let the query itself describe that intent.</p><h2 id="example-forward-relationship-payload-in-insert" tabindex="-1">Example: forward relationship payload in <code>INSERT</code> <a class="header-anchor" href="#example-forward-relationship-payload-in-insert" aria-label="Permalink to &quot;Example: forward relationship payload in \`INSERT\`&quot;">​</a></h2><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">INSERT INTO</span><span style="color:#BABED8;"> public.users</span></span>
<span class="line"><span style="color:#BABED8;">  (email, parent_user1 ~</span><span style="color:#89DDFF;">&gt;</span><span style="color:#BABED8;"> (id, email))</span></span>
<span class="line"><span style="color:#F78C6C;">VALUES</span></span>
<span class="line"><span style="color:#BABED8;">  (</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">ada@example.com</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">, </span><span style="color:#F78C6C;">ROW</span><span style="color:#BABED8;"> (</span><span style="color:#F78C6C;">50</span><span style="color:#BABED8;">, </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">parent@example.com</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">))</span></span></code></pre></div><p>How to read it:</p><ul><li><code>parent_user1</code> is a relationship-bearing column</li><li><code>~&gt; (id, email)</code> describes fields to write through that relationship</li><li><code>ROW (...)</code> supplies the payload for the related row shape</li></ul><h2 id="example-nested-forward-traversal" tabindex="-1">Example: nested forward traversal <a class="header-anchor" href="#example-nested-forward-traversal" aria-label="Permalink to &quot;Example: nested forward traversal&quot;">​</a></h2><p>Structured writes can compose through multiple hops.</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">INSERT INTO</span><span style="color:#BABED8;"> public.users</span></span>
<span class="line"><span style="color:#BABED8;">  (email, parent_user1 ~</span><span style="color:#89DDFF;">&gt;</span><span style="color:#BABED8;"> parent_user1 ~</span><span style="color:#89DDFF;">&gt;</span><span style="color:#BABED8;"> (id, email))</span></span>
<span class="line"><span style="color:#F78C6C;">VALUES</span></span>
<span class="line"><span style="color:#BABED8;">  (</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">ada@example.com</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">, </span><span style="color:#F78C6C;">ROW</span><span style="color:#BABED8;"> (</span><span style="color:#F78C6C;">50</span><span style="color:#BABED8;">, </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">root@example.com</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">))</span></span></code></pre></div><p>This is the kind of write that becomes very tedious in imperative application code.</p><h2 id="example-reverse-traversal-in-writes" tabindex="-1">Example: reverse traversal in writes <a class="header-anchor" href="#example-reverse-traversal-in-writes" aria-label="Permalink to &quot;Example: reverse traversal in writes&quot;">​</a></h2><p>Reverse traversal is also part of the model.</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">INSERT INTO</span><span style="color:#BABED8;"> public.users</span></span>
<span class="line"><span style="color:#BABED8;">  (email, (parent_user2 </span><span style="color:#89DDFF;">&lt;</span><span style="color:#BABED8;">~ users) ~</span><span style="color:#89DDFF;">&gt;</span><span style="color:#BABED8;"> (id, email))</span></span>
<span class="line"><span style="color:#F78C6C;">VALUES</span></span>
<span class="line"><span style="color:#BABED8;">  (</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">ada@example.com</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">, </span><span style="color:#F78C6C;">ROW</span><span style="color:#BABED8;"> (</span><span style="color:#F78C6C;">50</span><span style="color:#BABED8;">, </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">child@example.com</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">))</span></span></code></pre></div><p>Here, the target path is describing a dependent relationship from the opposite direction.</p><h2 id="example-structured-update" tabindex="-1">Example: structured <code>UPDATE</code> <a class="header-anchor" href="#example-structured-update" aria-label="Permalink to &quot;Example: structured \`UPDATE\`&quot;">​</a></h2><p>Structured writes are not limited to inserts.</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">UPDATE</span><span style="color:#BABED8;"> public.users </span><span style="color:#F78C6C;">AS</span><span style="color:#BABED8;"> u</span></span>
<span class="line"><span style="color:#F78C6C;">SET</span></span>
<span class="line"><span style="color:#BABED8;">  (username, parent_user1 ~</span><span style="color:#89DDFF;">&gt;</span><span style="color:#BABED8;"> id) </span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;"> ROW</span><span style="color:#BABED8;"> (</span><span style="color:#F78C6C;">232</span><span style="color:#BABED8;">, </span><span style="color:#F78C6C;">3445</span><span style="color:#BABED8;">)</span></span>
<span class="line"><span style="color:#F78C6C;">WHERE</span><span style="color:#BABED8;"> u.id </span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;"> 1</span></span></code></pre></div><p>This tells LinkedQL that the update affects:</p><ul><li>a direct column on the current row</li><li>and a related value reachable through <code>parent_user1</code></li></ul><h2 id="what-happens-internally" tabindex="-1">What happens internally <a class="header-anchor" href="#what-happens-internally" aria-label="Permalink to &quot;What happens internally&quot;">​</a></h2><p>Structured writes are not executed as magic. They are desugared into lower-level SQL plans.</p><p>That usually involves combinations of:</p><ul><li>CTEs</li><li><code>INSERT ... RETURNING</code></li><li><code>UPDATE</code></li><li>row-number bookkeeping to keep row-to-row correspondence stable</li></ul><p>This is why the feature belongs in the language and desugaring layer, not just in a helper library.</p><h2 id="relationship-to-deeprefs" tabindex="-1">Relationship to DeepRefs <a class="header-anchor" href="#relationship-to-deeprefs" aria-label="Permalink to &quot;Relationship to DeepRefs&quot;">​</a></h2><p>Structured writes build directly on <a href="/capabilities/deeprefs">DeepRefs</a>.</p><p>The rough rule is:</p><ul><li>DeepRefs in <code>SELECT</code> help you traverse and shape reads</li><li>DeepRefs in DML targets help you traverse and shape writes</li></ul><h2 id="relationship-to-upsert" tabindex="-1">Relationship to UPSERT <a class="header-anchor" href="#relationship-to-upsert" aria-label="Permalink to &quot;Relationship to UPSERT&quot;">​</a></h2><p>Structured writes can also combine with PostgreSQL-style upsert flows.</p><p>That matters in real applications because &quot;insert related data if absent, otherwise update it&quot; is one of the most common sources of verbose application-side glue.</p><p>See also: <a href="/capabilities/upsert">UPSERT</a></p><h2 id="current-practical-guidance" tabindex="-1">Current practical guidance <a class="header-anchor" href="#current-practical-guidance" aria-label="Permalink to &quot;Current practical guidance&quot;">​</a></h2><p>Because structured writes are powerful and nuanced, use this approach:</p><ul><li>start with one-hop writes first</li><li>then move to nested paths</li><li>prefer shapes that clearly mirror your relational model</li><li>validate complex write flows against your schema and tests</li></ul><p>This is one of the richest parts of the language surface, and also one of the places where precise examples matter most.</p><h2 id="related-docs" tabindex="-1">Related docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related docs&quot;">​</a></h2><ul><li><a href="/capabilities/deeprefs">DeepRefs</a></li><li><a href="/flashql/lang">FlashQL Language Reference</a></li><li><a href="/capabilities/upsert">UPSERT</a></li></ul>`,52)])])}const y=a(n,[["render",o]]);export{h as __pageData,y as default};
